    riskFactors: ["Female sex", "Family history of thyroid disease", "Autoimmune disorders (type 1 diabetes, pernicious anemia, Addison disease)", "Iodine excess (amiodarone, contrast)", "Smoking (increases risk of Graves ophthalmopathy)", "Postpartum period"],
