export function getEducation(diseaseId: string): DiseaseEducation {
  const entry = EDUCATION_REGISTRY[diseaseId];
  if (entry) return entry;
  return getFallbackEducation(diseaseId);
}

export function getAllEducation(): DiseaseEducation[] {
  return Object.values(EDUCATION_REGISTRY);
}
